}
fmt.Println(strings.Join(parts, " "))
```

answer_code:
package main

import (
	"fmt"
	"strconv"
	"strings"
)

func main() {
	var n int
	fmt.Scan(&n)
	var parts []string
	for i := 0; i < n; i++ {
		var x int
		fmt.Scan(&x)
		if x%2 == 0 {
			parts = append(parts, strconv.Itoa(x))
		}
	}
	fmt.Println(strings.Join(parts, " "))
}
